import React, { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useSocket } from '../../contexts/SocketContext';
import axios from 'axios';
import './CustomerDashboard.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const CustomerDashboard = () => {
  const { user } = useAuth();
  const { sensorData } = useSocket();
  const navigate = useNavigate();
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    totalSpent: 0,
    totalKg: 0,
    transactionCount: 0
  });

  useEffect(() => {
    fetchTransactions();
  }, []);

  const fetchTransactions = async () => {
    try {
      const response = await axios.get(`${API_URL}/transactions`);
      const data = response.data.data || response.data;
      setTransactions(data.slice(0, 3));
      
      const totalSpent = data.reduce((sum, t) => sum + (t.amountPaid || 0), 0);
      const totalKg = data.reduce((sum, t) => sum + (t.quantityKg || 0), 0);
      
      setStats({
        totalSpent,
        totalKg,
        transactionCount: data.length
      });
    } catch (error) {
      console.error('Error fetching transactions:', error);
    } finally {
      setLoading(false);
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      month: 'numeric',
      day: 'numeric',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
      hour12: true
    });
  };

  return (
    <div className="dashboard-container">
      {/* Main Content - Full Width */}
      <main className="main-content">
        {/* Welcome Section */}
        <div className="welcome-section">
          <h1 className="welcome-title">
            Welcome back, <span>{user?.firstName || 'User'}</span>!
          </h1>
          <p className="welcome-subtitle">Here's what's happening with your account</p>
        </div>

        {/* Stats Cards */}
        <div className="stats-grid">
          <div className="stat-card">
            <div className="stat-icon-wrapper">
              <span className="stat-icon">📊</span>
            </div>
            <div className="stat-content">
              <div className="stat-label">Total Transactions</div>
              <div className="stat-value">{stats.transactionCount}</div>
            </div>
          </div>

          <div className="stat-card">
            <div className="stat-icon-wrapper">
              <span className="stat-icon">💰</span>
            </div>
            <div className="stat-content">
              <div className="stat-label">Total Spent</div>
              <div className="stat-value">₱{stats.totalSpent.toFixed(2)}</div>
            </div>
          </div>

          <div className="stat-card">
            <div className="stat-icon-wrapper">
              <span className="stat-icon">🌾</span>
            </div>
            <div className="stat-content">
              <div className="stat-label">Total Rice</div>
              <div className="stat-value">{stats.totalKg.toFixed(2)} <span className="stat-unit">kg</span></div>
            </div>
          </div>
        </div>

        {/* Machine Status - Optional, only if sensorData exists */}
        {sensorData && (
          <div className="transactions-card">
            <h2 style={{ fontSize: '1.25rem', fontWeight: 600, marginBottom: '1rem', color: 'var(--gray-800)' }}>
              Machine Status
            </h2>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '1rem' }}>
              <div style={{ padding: '1rem', background: 'var(--gray-50)', borderRadius: '0.75rem' }}>
                <div style={{ color: 'var(--gray-500)', fontSize: '0.875rem', marginBottom: '0.25rem' }}>Sinandomeng</div>
                <div style={{ fontSize: '1.25rem', fontWeight: 600, color: 'var(--gray-800)' }}>
                  {sensorData.container1Level?.toFixed(1)} kg
                  <span style={{ 
                    marginLeft: '0.5rem', 
                    fontSize: '0.75rem', 
                    padding: '0.25rem 0.5rem', 
                    background: sensorData.container1Stock === 'OK' ? 'var(--primary-soft)' : 
                              sensorData.container1Stock === 'LOW' ? '#fef3c7' : '#fee2e2',
                    color: sensorData.container1Stock === 'OK' ? 'var(--primary)' : 
                           sensorData.container1Stock === 'LOW' ? '#d97706' : '#dc2626',
                    borderRadius: '9999px'
                  }}>
                    {sensorData.container1Stock}
                  </span>
                </div>
              </div>
              <div style={{ padding: '1rem', background: 'var(--gray-50)', borderRadius: '0.75rem' }}>
                <div style={{ color: 'var(--gray-500)', fontSize: '0.875rem', marginBottom: '0.25rem' }}>Dinorado</div>
                <div style={{ fontSize: '1.25rem', fontWeight: 600, color: 'var(--gray-800)' }}>
                  {sensorData.container2Level?.toFixed(1)} kg
                  <span style={{ 
                    marginLeft: '0.5rem', 
                    fontSize: '0.75rem', 
                    padding: '0.25rem 0.5rem', 
                    background: sensorData.container2Stock === 'OK' ? 'var(--primary-soft)' : 
                              sensorData.container2Stock === 'LOW' ? '#fef3c7' : '#fee2e2',
                    color: sensorData.container2Stock === 'OK' ? 'var(--primary)' : 
                           sensorData.container2Stock === 'LOW' ? '#d97706' : '#dc2626',
                    borderRadius: '9999px'
                  }}>
                    {sensorData.container2Stock}
                  </span>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Recent Transactions */}
        <div className="transactions-card">
          <div className="card-header">
            <h2>Recent Transactions</h2>
            <Link to="/customer/transactions" className="view-all-link">
              View All →
            </Link>
          </div>

          {loading ? (
            <div className="loading-spinner">Loading...</div>
          ) : transactions.length === 0 ? (
            <div className="loading-spinner">No transactions yet</div>
          ) : (
            <div className="transactions-list">
              {transactions.map((transaction) => (
                <div key={transaction._id} className="transaction-item">
                  <div className="transaction-info">
                    <div className="transaction-icon">🌾</div>
                    <div className="transaction-details">
                      <h3>{transaction.riceType} - {transaction.quantityKg}kg</h3>
                      <p>{formatDate(transaction.createdAt)}</p>
                    </div>
                  </div>
                  <div className="transaction-amount">
                    <div className="transaction-price">₱{transaction.amountPaid}</div>
                    <Link 
                      to={`/customer/rate/${transaction.transactionId}`}
                      className="transaction-rate"
                    >
                      Rate this purchase
                    </Link>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Quick Actions */}
        <div className="quick-actions">
          <Link to="/customer/returns/create" className="action-card">
            <div className="action-icon-wrapper">
              <span className="action-icon">↩️</span>
            </div>
            <h3>Request Return</h3>
            <p>Return a product if you're not satisfied</p>
          </Link>

          <Link to="/customer/messages" className="action-card">
            <div className="action-icon-wrapper">
              <span className="action-icon">💬</span>
            </div>
            <h3>Contact Support</h3>
            <p>Send us a message or ask for help</p>
          </Link>
        </div>
      </main>
    </div>
  );
};

export default CustomerDashboard;
